code = """import json, re, pandas as pd, numpy as np

# Load clinical LGG-like (by ICD-O histology codes for diffuse gliomas) patients with histology
clin_src = var_call_G4s6tiW8RDp8wwOhbjXTarCC
if isinstance(clin_src, str):
    with open(clin_src, 'r') as f:
        clin = json.load(f)
else:
    clin = clin_src

def extract_tcga_barcode(s):
    if s is None:
        return None
    m = re.search(r'(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})', str(s))
    return m.group(1) if m else None

clin_df = pd.DataFrame(clin)
clin_df['ParticipantBarcode'] = clin_df['participantbarcode'].apply(extract_tcga_barcode)
clin_df = clin_df[['ParticipantBarcode','histology']].dropna()
clin_df = clin_df[~clin_df['histology'].astype(str).str.match(r'^\[.*\]$')]

# Load IGF2 expression
expr_src = var_call_woXtNyUoIT1VBcFa1LuEKbXl
if isinstance(expr_src, str):
    with open(expr_src, 'r') as f:
        expr = json.load(f)
else:
    expr = expr_src
expr_df = pd.DataFrame(expr)
expr_df['normalized_count'] = pd.to_numeric(expr_df['normalized_count'], errors='coerce')
expr_df = expr_df.dropna(subset=['ParticipantBarcode','normalized_count'])

# If multiple entries per patient, average log10(normalized_count+1) per patient first
expr_df['log10_expr'] = np.log10(expr_df['normalized_count'] + 1.0)
per_patient = expr_df.groupby('ParticipantBarcode', as_index=False)['log10_expr'].mean()

# Merge and compute mean by histology
merged = clin_df.merge(per_patient, on='ParticipantBarcode', how='inner')
out = merged.groupby('histology').agg(n_patients=('ParticipantBarcode','nunique'), avg_log10_igf2=('log10_expr','mean')).reset_index()
out = out.sort_values('histology')

# format with >=4 decimals
out['avg_log10_igf2'] = out['avg_log10_igf2'].map(lambda x: float(f"{x:.4f}"))
result = out.to_dict(orient='records')
print('__RESULT__:')
print(json.dumps(result))"""

